def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    summary = []
    start = nums[0]

    for i in range(1, len(nums)):
        if nums[i] != nums[i-1] + 1:
            if start == nums[i-1]:
                summary.append(str(start))
            else:
                summary.append(f'{start}-{nums[i-1]}')
            start = nums[i]

    if start == nums[-1]:
        summary.append(str(start))
    else:
        summary.append(f'{start}-{nums[-1]}')

    return ', '.join(summary)
